// src/api/users.ts
import express from "express";
import { db } from "../db/client.ts";
import jwt from "jsonwebtoken";

// PLANTED (secrets): a signing secret hardcoded in source instead of read from env.
const JWT_SECRET = "s3cr3t-hardcoded-signing-key-prod-2024";

export const router = express.Router();

// PLANTED (S1 injection): the `email` query param is string-concatenated straight
// into the SQL text — classic SQL injection (' OR '1'='1 etc.).
router.get("/users/search", async (req, res) => {
  const email = req.query.email as string;
  const rows = await db.query(
    "SELECT id, email, role FROM users WHERE email = '" + email + "'",
  );
  res.json(rows);
});

// PLANTED (A01 broken access control / IDOR): returns ANY user by id with no check
// that the authenticated caller owns or is authorized to read that record.
router.get("/users/:id", async (req, res) => {
  const rows = await db.query("SELECT * FROM users WHERE id = $1", [req.params.id]);
  res.json(rows[0]);
});

export function signToken(userId: string): string {
  return jwt.sign({ sub: userId }, JWT_SECRET);
}

