export const db = {
  // Parameterized when called as query(text, params); vulnerable only if the
  // CALLER concatenates user input into `text` themselves.
  async query(_text: string, _params?: unknown[]): Promise<any[]> {
    return [];
  },
};

// src/api/orders.ts
import express from "express";
import { db } from "../db/client.ts";

// SAFE (decoy): secret is read from the environment, NOT hardcoded. Must NOT be
// flagged as a hardcoded secret.
const STRIPE_SECRET_KEY = process.env.STRIPE_SECRET_KEY ?? "";

export const router = express.Router();

function requireAuth(
  req: express.Request & { user?: { id: string } },
  res: express.Response,
  next: express.NextFunction,
) {
  if (!(req as any).user) {
    res.status(401).end();
    return;
  }
  next();
}

// SAFE (decoy): fully parameterized query ($1, $2) AND scoped to the caller's own
// customer_id — no SQL injection and no IDOR. Must NOT be flagged as SQLi or IDOR.
router.get("/orders/:id", requireAuth, async (req: any, res) => {
  const rows = await db.query(
    "SELECT * FROM orders WHERE id = $1 AND customer_id = $2",
    [req.params.id, req.user.id],
  );
  res.json(rows[0]);
});

// PLANTED (S3 SSRF): fetches a fully attacker-controlled URL with no allowlist,
// scheme check, or private-range block — reaches internal metadata endpoints
// (e.g. http://169.254.169.254/) and internal services.
router.post("/orders/import", requireAuth, async (req: any, res) => {
  const resp = await fetch(req.body.sourceUrl);
  const data = await resp.json();
  res.json({ imported: data, keyPresent: STRIPE_SECRET_KEY.length > 0 });
});

// src/db/client.ts  (thin pg-style client stub)
export const db = {
  // Parameterized when called as query(text, params); vulnerable only if the
  // CALLER concatenates user input into `text` themselves.
  async query(_text: string, _params?: unknown[]): Promise<any[]> {
    return [];
  },
};
